import { forwardRef, useState } from 'react';
import { Eye, EyeOff } from 'lucide-react';
import { Label } from '@/shadcn/components/ui/label';
import { FieldError } from '@/shadcn/components/ui/field';
import {
    InputGroup,
    InputGroupAddon,
    InputGroupButton,
    InputGroupInput,
} from '@/shadcn/components/ui/input-group';

interface HarmonyInputProps extends React.InputHTMLAttributes<HTMLInputElement> {
    label?: string;
    error?: string;
    leftIcon?: React.ReactNode;
    rightIcon?: React.ReactNode;
}

export const HarmonyInput = forwardRef<HTMLInputElement, HarmonyInputProps>(
    ({ label, error, leftIcon, rightIcon, type, className, id, ...props }, ref) => {
        const [showPassword, setShowPassword] = useState(false);
        const isPassword = type === 'password';
        const resolvedType = isPassword ? (showPassword ? 'text' : 'password') : type;

        return (
            <div className="w-full space-y-1.5">
                {label && (
                    <Label htmlFor={id}>
                        {label}
                    </Label>
                )}
                <InputGroup aria-invalid={error ? true : undefined} className="overflow-hidden">
                    {leftIcon && (
                        <InputGroupAddon align="inline-start" className="pr-2">
                            {leftIcon}
                        </InputGroupAddon>
                    )}
                    <InputGroupInput
                        ref={ref}
                        id={id}
                        type={resolvedType}
                        aria-invalid={error ? true : undefined}
                        className={className}
                        {...props}
                    />
                    {(isPassword || rightIcon) && (
                        <InputGroupAddon align="inline-end" className="pl-0.5">
                            {isPassword ? (
                                <InputGroupButton
                                    onClick={() => setShowPassword(v => !v)}
                                    aria-label={showPassword ? 'Hide password' : 'Show password'}
                                >
                                    {showPassword ? <EyeOff /> : <Eye />}
                                </InputGroupButton>
                            ) : rightIcon}
                        </InputGroupAddon>
                    )}
                </InputGroup>
                {error && <FieldError>{error}</FieldError>}
            </div>
        );
    }
);

HarmonyInput.displayName = 'HarmonyInput';
